122	 * GET /authCallback
123	 * OAuth callback from Google. Exchanges code for custom token.
124	 * Input: { code, state }
125	 * Side-effect: Stores one-time custom token in session
126	 * Redirects to: divergent-todos://auth/callback?sid=...
127	 */
128	export const authCallback = onRequest(
129	  {
130	    region: "us-central1",
131	    cors: true,
132	    maxInstances: 10,
133	    secrets: [googleClientId, googleClientSecret],
134	  },
135	  async (req, res) => {
136	    try {
137	      const code = req.query.code as string;
138	      const state = req.query.state as string;
139	
140	      if (!code || !state) {
141	        throw new Error("Missing code or state parameter");
142	      }
143	
144	      // Find session by state
145	      const sessionsSnapshot = await db
146	        .collection(SESSIONS_COLLECTION)
147	        .where("state", "==", state)
148	        .where("used", "==", false)
149	        .limit(1)
150	        .get();
151	
152	      if (sessionsSnapshot.empty) {
153	        throw new Error("Invalid or expired state");
154	      }
155	
156	      const sessionDoc = sessionsSnapshot.docs[0];
157	      const session = sessionDoc.data() as AuthSession;
158	
159	      // Verify session not expired
160	      if (Date.now() - session.createdAt > SESSION_TTL_MS) {
161	        await sessionDoc.ref.delete();
162	        throw new Error("Session expired");
163	      }
164	
165	      // Mark state as used (prevent replay)
166	      await sessionDoc.ref.update({ used: true });
167	
168	      // Exchange code for tokens
169	      const oauth2Client = getOAuth2Client(
170	        googleClientId.value(),
171	        googleClientSecret.value()
172	      );
173	      const { tokens } = await oauth2Client.getToken(code);
174	
175	      if (!tokens.id_token) {
176	        throw new Error("No ID token returned from Google");
177	      }
178	
179	      // Verify ID token
180	      const ticket = await oauth2Client.verifyIdToken({
181	        idToken: tokens.id_token,
182	        audience: googleClientId.value(),
183	      });
184	
185	      const payload = ticket.getPayload();
186	      if (!payload || !payload.email) {
187	        throw new Error("Invalid token payload");
188	      }
189	
190	      const { email, name, picture } = payload;
