628	/**
629	 * deleteTestUser
630	 * Deletes a test user and all associated data.
631	 * Safety check: Only deletes users marked with isTestUser flag.
632	 */
633	export const deleteTestUser = onCall(
634	  {
635	    region: "us-central1",
636	    cors: ["*"],
637	    maxInstances: 10,
638	  },
639	  async (req) => {
640	    try {
641	      const { uid } = req.data;
642	
643	      if (!uid) {
644	        throw new HttpsError("invalid-argument", "uid is required");
645	      }
646	
647	      // Safety check: verify it's actually a test user by checking custom claims
648	      const userRecord = await auth.getUser(uid);
649	      const customClaims = userRecord.customClaims || {};
650	
651	      if (!customClaims.isTestUser) {
652	        throw new HttpsError(
653	          "permission-denied",
654	          "Cannot delete non-test user"
655	        );
656	      }
657	
658	      // Delete user data from Firestore
659	      const batch = db.batch();
660	
661	      // Delete todos
662	      const todos = await db.collection("todos")
663	        .where("userId", "==", uid)
664	        .get();
665	      todos.docs.forEach((doc) => batch.delete(doc.ref));
666	
667	      // Delete activity
668	      const activity = await db.collection("activity")
669	        .where("userId", "==", uid)
670	        .get();
671	      activity.docs.forEach((doc) => batch.delete(doc.ref));
672	
673	      // Delete profile
