685	
686	      logger.info("Test user deleted successfully", { uid });
687	
688	      return { success: true };
689	    } catch (error) {
690	      logger.error("Failed to delete test user", error);
691	      throw new HttpsError(
692	        "internal",
693	        `Failed to delete test user: ${error instanceof Error ? error.message : "Unknown error"}`
694	      );
695	    }
696	  }
