714	  const sub = snap.exists ? (snap.data()?.subscription ?? {}) : {};
715	
716	  if (sub?.customerId) return sub.customerId as string;
717	
718	  const customer = await stripe.customers.create({
719	    email: email ?? undefined,
720	    metadata: { firebaseUID: uid },
721	  });
722	
723	  await ref.set(
724	    {
725	      subscription: {
726	        customerId: customer.id,
727	        subscriptionId: null,
728	        status: null,
729	        cancelAtPeriodEnd: false,
730	        currentPeriodEnd: null,
731	      },
732	    },
733	    { merge: true }
734	  );
735	
736	  return customer.id;
737	}
