802	      : STRIPE_PRICE_ID.value();
803	
804	    const stripe = stripeFrom(stripeApiKey);
805	    if (!priceId) throw new HttpsError("failed-precondition", "Missing price.");
806	
807	    const email = req.auth?.token?.email ?? null;
808	    const customerId = await getOrCreateCustomer(stripe, uid, email);
809	
810	    // Validate URLs - only accept HTTPS URLs or use defaults
811	    const isValidUrl = (url: string | undefined) => {
812	      if (!url) return false;
