987	      STRIPE_TEST_API_KEY,
988	      STRIPE_TEST_WEBHOOK_SECRET
989	    ]
990	  },
991	  async (req, res) => {
992	    const sig = req.headers["stripe-signature"];
993	    if (!sig) {
994	      res.status(400).send("Missing stripe-signature");
995	      return;
996	    }
997	
998	    // Try to verify signature with both test and live secrets
999	    let event: Stripe.Event | null = null;
1000	    let isTestMode = false;
1001	
1002	    // Try live mode first
1003	    try {
1004	      const liveStripe = stripeFrom(STRIPE_API_KEY.value());
1005	      event = liveStripe.webhooks.constructEvent(
1006	        req.rawBody,
1007	        sig as string,
1008	        STRIPE_WEBHOOK_SECRET.value()
1009	      );
1010	      isTestMode = false;
1011	      logger.info("Webhook verified with live mode secret");
1012	    } catch (liveErr: any) {
1013	      // Try test mode
1014	      try {
1015	        const testStripe = stripeFrom(STRIPE_TEST_API_KEY.value());
1016	        event = testStripe.webhooks.constructEvent(
1017	          req.rawBody,
1018	          sig as string,
1019	          STRIPE_TEST_WEBHOOK_SECRET.value()
1020	        );
1021	        isTestMode = true;
1022	        logger.info("Webhook verified with test mode secret");
1023	      } catch (testErr: any) {
1024	        logger.error("Invalid signature for both test and live modes", {
1025	          liveError: liveErr?.message,
1026	          testError: testErr?.message,
1027	        });
1028	        res.status(400).send(`Webhook Error: Invalid signature`);
1029	        return;
1030	      }
1031	    }
1032	
1033	    if (!event) {
1034	      res.status(400).send("Failed to construct event");
1035	      return;
1036	    }
1037	
1038	    // Use appropriate Stripe instance based on detected mode
1039	    const stripe = stripeFrom(
1040	      isTestMode ? STRIPE_TEST_API_KEY.value() : STRIPE_API_KEY.value()
1041	    );
1042	
1043	    try {
1044	      logger.info("Processing webhook event", {
1045	        type: event.type,
1046	        mode: isTestMode ? "test" : "live",
1047	        eventId: event.id,
1048	      });
1049	
1050	      switch (event.type) {
1051	        case "checkout.session.completed": {
1052	          const session = event.data.object as Stripe.Checkout.Session;
1053	          const { uid, subscription } = await uidFromCheckoutSession(stripe, session);
1054	          if (uid && subscription) await writeSubscription(uid, subscription);
1055	          break;
1056	        }
1057	        case "customer.subscription.created":
1058	        case "customer.subscription.updated":
1059	        case "customer.subscription.deleted": {
1060	          const sub = event.data.object as Stripe.Subscription;
1061	          const uid = await uidFromSubscription(stripe, sub);
1062	          if (uid) await writeSubscription(uid, sub);
1063	          break;
1064	        }
1065	        case "invoice.paid": {
1066	          const invoice = event.data.object as Stripe.Invoice;
1067	          const invoiceAny = invoice as any;
1068	          let uid: string | undefined;
1069	          if (invoiceAny.subscription) {
1070	            const sub = await stripe.subscriptions.retrieve(invoiceAny.subscription.toString());
1071	            uid = (sub.metadata?.firebaseUID as string | undefined);
1072	            if (!uid && invoice.customer) {
1073	              const cust = await stripe.customers.retrieve(invoice.customer.toString());
1074	              if (!("deleted" in cust) && cust.metadata?.firebaseUID) {
1075	                uid = cust.metadata.firebaseUID as string;
1076	              }
1077	            }
1078	          } else if (invoice.customer) {
1079	            const cust = await stripe.customers.retrieve(invoice.customer.toString());
1080	            if (!("deleted" in cust) && cust.metadata?.firebaseUID) {
1081	              uid = cust.metadata.firebaseUID as string;
1082	            }
1083	          }
1084	          if (uid) await writePayment(uid, invoice);
1085	          break;
1086	        }
1087	        default:
1088	          break;
1089	      }
1090	
1091	      res.json({ received: true });
1092	    } catch (err) {
1093	      logger.error("Webhook handler error", err);
1094	      res.status(500).send("Webhook handler error");
1095	    }
1096	  }
